  "type": "array",
  "description": "The list of processed trade records containing extracted models and classifications.",
  "items": {
    "type": "object",
    "properties": {
      "row_id": {
        "type": "string",
        "description": "The exact row_id provided in the input data."
      },
      "Manufacturer": {
        "type": "string",
        "description": "The clean, primary brand name of the equipment creator."
      },
      "Product_Type": {
        "type": "string",
        "description": "The classified core equipment instrument category."
      },
      "Model": {
        "type": "string",
        "description": "The isolated hardware/software model number string, or 'NotFound'."
      },
      "Competitor_Check": {
        "type": "string",
        "enum": [
          "Ours",
          "SAM",
          "Non-SAM"
        ]
      },
      "Confidence_Score": {
        "type": "number",
        "minimum": 0,
        "maximum": 1
      },
      "Match_Reason": {
        "type": "string",
        "description": "A short precise explanation of how the record was classified."
      }
    },
    "required": [
      "row_id",
      "Manufacturer",
      "Product_Type",
      "Model",
      "Competitor_Check",
      "Confidence_Score",
      "Match_Reason"
    ],
    "additionalProperties": false
  }
}

parameters.jsCode:
// Grabs the array the AI made and turns it back into individual n8n items
return $input.first().json.output.map(item => {
    return { json: item };
});

// 1. Grab the package of items we squashed in the Main Workflow
const batchRecords = $input.first().json.batch_records;

// 2. Loop through the batch and generate a fake "AI" response for every single row
const simulatedAiResponse = batchRecords.map(record => {
    return {
        // CRITICAL: We pass the exact row_id back so the Merge node doesn't break
        "row_id": record.row_id, 

        // Simulating the exact schema you built for Groq
        "Manufacturer": "Test_Brand_Corp",
        "Product_Type": "Simulated Instrument",
        "Model": record.Raw_Model || "Mock-Model-X",
        "Competitor_Check": "SAM",
        "Confidence_Score": 0.99,
        "Match_Reason": "Simulated test run to verify loop plumbing."
    };
});

// 3. Package the fake answers into the exact 'output' envelope the Unwrap node is looking for
return [{
    json: {
        output: simulatedAiResponse
    }
}];

// 1. Grab the single output box from the AI Agent
const aiResponse = $input.first().json.output;

// 2. Map over the array of 10 answers and wrap each one in n8n's required 'json' format
const unbundledItems = aiResponse.map(item => {
    return {
        json: item
    };
});

// 3. Return the 10 separate rows to the workflow
return unbundledItems;

